patch:
--- filters/f_decoder_wrapper.c
+++ filters/f_decoder_wrapper.c
@@ -1234,6 +1234,10 @@
     if (opts->vdec_queue_opts && opts->vdec_queue_opts->use_queue) {
         // Check if the queue is full before decoding a new packet
         if (queue_get_size(decf->queue) >= opts->vdec_queue_opts->max_bytes) {
+            // If the queue is full, flush it to prevent hanging
+            mp_filter_internal_mark_ready(decf);
+            mp_filter_flush(decf);
             return 0;
         }
     }
